import json
# Access the business data
business_result = var_functions['query_db:8']

# Filter businesses that accept credit cards
credit_card_businesses = []
for business in business_result:
    if isinstance(business.get('attributes'), dict):
        if business['attributes'].get('BusinessAcceptsCreditCards') == 'True':
            credit_card_businesses.append(business)

# Extract categories from description and count
from collections import Counter
category_counts = Counter()

for business in credit_card_businesses:
    desc = business.get('description', '')
    # Extract categories from description (they're usually after "services in" or similar)
    if 'services in' in desc:
        categories_part = desc.split('services in')[1]
        # Split by commas and 'and' to get individual categories
        categories = categories_part.replace('and', ',').split(',')
        for cat in categories:
            cat = cat.strip()
            if cat and cat not in ['this facility offers', 'this establishment offers', 'a range of services']:
                # Remove common prefixes
                if cat.startswith('in '):
                    cat = cat[3:]
                if cat.endswith('.'):
                    cat = cat[:-1]
                category_counts[cat] += 1

# Get the most common category
if category_counts:
    most_common = category_counts.most_common(1)[0]
else:
    most_common = (None, 0)

print('__RESULT__:')
print(json.dumps({
    "total_credit_card_businesses": len(credit_card_businesses),
    "most_common_category": most_common[0],
    "count_in_category": most_common[1]
}))

